class Solution:
    def specialPerm(self, nums):
        import itertools
        MOD = 10 ** 9 + 7
        count = 0
        for perm in itertools.permutations(nums):
            ok = True
            for i in range(len(perm) - 1):
                if perm[i] % perm[i + 1] != 0 and perm[i + 1] % perm[i] != 0:
                    ok = False
                    break
            if ok:
                count += 1
        return count % MOD

