class Solution:
    def specialPerm(self, nums):
        MOD = 10 ** 9 + 7
        n = len(nums)
        dp = [[0] * n for _ in range(1 << n)]
        for i in range(n):
            dp[1 << i][i] = 1
        for mask in range(1 << n):
            row = dp[mask]
            for last in range(n):
                cur = row[last]
                if not cur:
                    continue
                for nxt in range(n):
                    if mask & (1 << nxt):
                        continue
                    if nums[last] % nums[nxt] == 0 or nums[nxt] % nums[last] == 0:
                        nmask = mask | (1 << nxt)
                        dp[nmask][nxt] = (dp[nmask][nxt] + cur) % MOD
        full = (1 << n) - 1
        return sum(dp[full]) % MOD

