var specialPerm = function(nums) {
    const MOD = 1000000007n;
    const n = nums.length;
    const size = 1 << n;
    const dp = Array.from({ length: size }, () => new Array(n).fill(0n));
    for (let i = 0; i < n; i++) dp[1 << i][i] = 1n;
    for (let mask = 0; mask < size; mask++) {
        for (let last = 0; last < n; last++) {
            const cur = dp[mask][last];
            if (cur === 0n) continue;
            for (let nxt = 0; nxt < n; nxt++) {
                if (mask & (1 << nxt)) continue;
                if (nums[last] % nums[nxt] === 0 || nums[nxt] % nums[last] === 0) {
                    const nmask = mask | (1 << nxt);
                    dp[nmask][nxt] = (dp[nmask][nxt] + cur) % MOD;
                }
            }
        }
    }
    const full = size - 1;
    let total = 0n;
    for (let last = 0; last < n; last++) total = (total + dp[full][last]) % MOD;
    return Number(total);
};
